class SimpleRAG:
    def __init__(self, documents, chunk_size=50, overlap=10):
        self.chunks = []
        for doc in documents:
            self.chunks.extend(self._chunk_text(doc, chunk_size, overlap))

    def _chunk_text(self, text, size, overlap):
        words = text.split()
        chunks = []
        step = max(size - overlap, 1)
        for i in range(0, len(words), step):
            chunks.append(" ".join(words[i:i+size]))
        return chunks

    def _similarity(self, query, chunk):
        return len(set(query.lower().split()) & set(chunk.lower().split()))

    def retrieve(self, query, k=3):
        scored = sorted(self.chunks, key=lambda c: self._similarity(query, c), reverse=True)
        return scored[:k]

